;\n      NEXT_PASS (pass_lower_bitint);\n      NEXT_PASS (pass_lower_vector_ssa);\n      NEXT_PASS (pass_lower_switch);\n      /* Perform simple scalar cleanup which is constant/copy propagation.  */\n      NEXT_PASS (pass_ccp, true /* nonzero_p */);\n      NEXT_PASS (pass_post_ipa_warn);\n      NEXT_PASS (pass_object_sizes);\n      NEXT_PASS (pass_strlen);\n      /* Fold remaining builtins.  */\n      NEXT_PASS (pass_forwprop, /*full_walk=*/false, /*last=*/true);\n      NEXT_PASS (pass_dce);\n      /* Profile count may overflow as a result of inlinining very large\n         loop nests.  This pass should run before any late pass that makes\n\t use of profile.  */\n      NEXT_PASS (pass_rebuild_frequencies);\n      NEXT_PASS (pass_sancov);\n      NEXT_PASS (pass_asan);\n      NEXT_PASS (pass_tsan);\n      /* ???  We do want some kind of loop invariant motion, but we possibly\n         need to adjust LIM to be more friendly towards preserving accurate\n\t debug information here.  */\n      /* Split critical edges before late uninit warning to reduce the\n         number of false positives from it.  */\n      NEXT_PASS (pass_split_crit_edges);\n      NEXT_PASS (pass_late_warn_uninitialized);\n      /* uncprop replaces constants by SSA names.  This makes analysis harder\n\t and thus it should be run last.  */\n      NEXT_PASS (pass_uncprop);\n  POP_INSERT_PASSES ()\n  NEXT_PASS (pass_assumptions);\n  NEXT_PASS (pass_tm_init);\n  PUSH_INSERT_PASSES_WITHIN (pass_tm_init)\n      NEXT_PASS (pass_tm_mark);\n      NEXT_PASS (pass_tm_memopt);\n      NEXT_PASS (pass_tm_edges);\n  POP_INSERT_PASSES ()\n  NEXT_PASS (pass_simduid_cleanup);\n  NEXT_PASS (pass_vtable_verify);\n  NEXT_PASS (pass_lower_vaarg);\n  NEXT_PASS (pass_lower_vector);\n  NEXT_PASS (pass_lower_complex_O0);\n  NEXT_PASS (pass_lower_bitint_O0);\n  NEXT_PASS (pass_sancov_O0);\n  NEXT_PASS (pass_lower_switch_O0);\n  NEXT_PASS (pass_asan_O0);\n  NEXT_PASS (pass_tsan_O0);\n  NEXT_PASS (pass_musttail);\n  NEXT_PASS (pass_sanopt);\n  NEXT_PASS (pass_cleanup_eh);\n  NEXT_PASS (pass_lower_resx);\n  NEXT_PASS (pass_nrv);\n  NEXT_PASS (pass_gimple_isel);\n  NEXT_PASS (pass_harden_conditional_branches);\n  NEXT_PASS (pass_harden_compares);\n  NEXT_PASS (pass_warn_access, /*early=*/false, /*check_dangling=*/false);\n  NEXT_PASS (pass_cleanup_cfg_post_optimizing);\n  NEXT_PASS (pass_warn_function_noreturn);\n\n  NEXT_PASS (pass_expand);\n\n  NEXT_PASS (pass_rest_of_compilation);\n  PUSH_INSERT_PASSES_WITHIN (pass_rest_of_compilation)\n      NEXT_PASS (pass_instantiate_virtual_regs);\n      NEXT_PASS (pass_into_cfg_layout_mode);\n      NEXT_PASS (pass_jump);\n      NEXT_PASS (pass_lower_subreg);\n      NEXT_PASS (pass_df_initialize_opt);\n      NEXT_PASS (pass_cse);\n      NEXT_PASS (pass_rtl_fwprop);\n      NEXT_PASS (pass_rtl_cprop);\n      NEXT_PASS (pass_rtl_pre);\n      NEXT_PASS (pass_rtl_hoist);\n      NEXT_PASS (pass_hardreg_pre);\n      NEXT_PASS (pass_rtl_cprop);\n      NEXT_PASS (pass_rtl_store_motion);\n      NEXT_PASS (pass_cse_after_global_opts);\n      NEXT_PASS (pass_rtl_ifcvt);\n      NEXT_PASS (pass_reginfo_init);\n      /* Perform loop optimizations.  It might be better to do them a bit\n\t sooner, but we want the profile feedback to work more\n\t efficiently.  */\n      NEXT_PASS (pass_loop2);\n      PUSH_INSERT_PASSES_WITHIN (pass_loop2)\n\t  NEXT_PASS (pass_rtl_loop_init);\n\t  NEXT_PASS (pass_rtl_move_loop_invariants);\n\t  NEXT_PASS (pass_rtl_unroll_loops);\n\t  NEXT_PASS (pass_rtl_doloop);\n\t  NEXT_PASS (pass_rtl_loop_done);\n      POP_INSERT_PASSES ()\n      NEXT_PASS (pass_lower_subreg2);\n      NEXT_PASS (pass_web);\n      NEXT_PASS (pass_rtl_cprop);\n      NEXT_PASS (pass_cse2);\n      NEXT_PASS (pass_rtl_dse1);\n      NEXT_PASS (pass_rtl_fwprop_addr);\n      NEXT_PASS (pass_inc_dec);\n      NEXT_PASS (pass_initialize_regs);\n      NEXT_PASS (pass_ud_rtl_dce);\n      NEXT_PASS (pass_ext_dce);\n      NEXT_PASS (pass_combine);\n      NEXT_PASS (pass_late_combine);\n      NEXT_PASS (pass_if_after_combine);\n      NEXT_PASS (pass_jump_after_combine);\n      NEXT_PASS (pass_partition_blocks);\n      NEXT_PASS (pass_outof_cfg_layout_mode);\n      NEXT_PASS (pass_split_all_insns);\n      NEXT_PASS (pass_lower_subreg3);\n      NEXT_PASS (pass_df_initialize_no_opt);\n      NEXT_PASS (pass_stack_ptr_mod);\n      NEXT_PASS (pass_mode_switching);\n      NEXT_PASS (pass_match_asm_constraints);\n      NEXT_PASS (pass_sms);\n      NEXT_PASS (pass_live_range_shrinkage);\n      NEXT_PASS (pass_sched);\n      NEXT_PASS (pass_rtl_avoid_store_forwarding);\n      NEXT_PASS (pass_early_remat);\n      NEXT_PASS (pass_dep_fusion);\n      NEXT_PASS (pass_ira);\n      NEXT_PASS (pass_reload);\n      /* In the following, some passes are tied to 'pass_postreload' and others\n\t to 'pass_late_compilation'.  The difference is that the latter also\n\t run for 'targetm.no_register_allocation' targets.  */\n      NEXT_PASS (pass_postreload);\n      PUSH_INSERT_PASSES_WITHIN (pass_postreload)\n\t  NEXT_PASS (pass_postreload_cse);\n\t  NEXT_PASS (pass_late_combine);\n\t  NEXT_PASS (pass_gcse2);\n\t  NEXT_PASS (pass_split_after_reload);\n\t  NEXT_PASS (pass_ree);\n\t  NEXT_PASS (pass_compare_elim_after_reload);\n\t  NEXT_PASS (pass_thread_prologue_and_epilogue);\n\t  NEXT_PASS (pass_rtl_dse2);\n\t  NEXT_PASS (pass_stack_adjustments);\n\t  NEXT_PASS (pass_jump2);\n\t  NEXT_PASS (pass_duplicate_computed_gotos);\n\t  NEXT_PASS (pass_sched_fusion);\n\t  NEXT_PASS (pass_peephole2);\n\t  NEXT_PASS (pass_if_after_reload);\n\t  NEXT_PASS (pass_dep_fusion);\n\t  NEXT_PASS (pass_regrename);\n\t  NEXT_PASS (pass_fold_mem_offsets);\n\t  NEXT_PASS (pass_cprop_hardreg);\n\t  NEXT_PASS (pass_fast_rtl_dce);\n\t  NEXT_PASS (pass_reorder_blocks);\n\t  NEXT_PASS (pass_leaf_regs);\n\t  NEXT_PASS (pass_split_before_sched2);\n\t  NEXT_PASS (pass_sched2);\n\t  NEXT_PASS (pass_stack_regs);\n\t  PUSH_INSERT_PASSES_WITHIN (pass_stack_regs)\n\t      NEXT_PASS (pass_split_before_regstack);\n\t      NEXT_PASS (pass_stack_regs_run);\n\t  POP_INSERT_PASSES ()\n      POP_INSERT_PASSES ()\n      NEXT_PASS (pass_late_thread_prologue_and_epilogue);\n      /* No target-independent code motion is allowed beyond this point,\n         excepting the legacy delayed-branch pass.  */\n      NEXT_PASS (pass_late_compilation);\n      PUSH_INSERT_PASSES_WITHIN (pass_late_compilation)\n\t  NEXT_PASS (pass_zero_call_used_regs);\n\t  NEXT_PASS (pass_compute_alignments);\n\t  NEXT_PASS (pass_variable_tracking);\n\t  NEXT_PASS (pass_free_cfg);\n\t  NEXT_PASS (pass_machine_reorg);\n\t  NEXT_PASS (pass_cleanup_barriers);\n\t  NEXT_PASS (pass_delay_slots);\n\t  NEXT_PASS (pass_split_for_shorten_branches);\n\t  NEXT_PASS (pass_convert_to_eh_region_ranges);\n\t  NEXT_PASS (pass_shorten_branches);\n\t  NEXT_PASS (pass_set_nothrow_function_flags);\n\t  NEXT_PASS (pass_dwarf2_frame);\n\t  NEXT_PASS (pass_final);\n      POP_INSERT_PASSES ()\n      NEXT_PASS (pass_df_finish);\n  POP_INSERT_PASSES ()\n  NEXT_PASS (pass_clean_state);\n  TERMINATE_PASS_LIST (all_passes)\n", "numLines": 578, "startLine": 1, "totalLines": 578}}

