   108→   version is meant to be used for the gen* programs and therefor need not
   109→   handle subdirectories.  */
   110→
   111→const char *
   112→trim_filename (const char *name)
   113→{
   114→  static const char this_file[] = __FILE__;
   115→  const char *p = name, *q = this_file;
   116→
   117→  /* Skip any parts the two filenames have in common.  */
   118→  while (*p == *q && *p != 0 && *q != 0)
   119→    p++, q++;
   120→
   121→  /* Now go backwards until the previous directory separator.  */
   122→  while (p > name && !IS_DIR_SEPARATOR (p[-1]))
   123→    p--;
   124→
   125→  return p;
