   829→  if (file == stderr && global_dc)
   830→    if (!global_dc->supports_fnotice_on_stderr_p ())
   831→      return;
   832→
   833→  va_list ap;
   834→
   835→  va_start (ap, cmsgid);
   836→  vfprintf (file, _(cmsgid), ap);
   837→  va_end (ap);
   838→}
